// Gera 125 itens com ticket_ids unicos
const items = [];
for (let i = 0; i < 125; i++) {
  items.push({
    json: {
      index: i,
      payload: {
        ticket_id: `RATELIMIT-${Date.now()}-${i}`,
        cliente: `Cliente Rate Test ${i}`,
        canal: 'api',
        mensagens: `Mensagem de teste rate limit numero ${i}`,
        tecnico: 'n8n-rl-test',
        metadata: {
          sourceSystem: 'n8n-rate-test',
          sourceEntityId: `RL-ENTITY-${Date.now()}-${i}`,
          tenantId: 'rl-tenant',
          ingestionId: `ing-rl-${Date.now()}-${i}`
        }
      }
    }
  });
}
return items;

// Agrega resultados e conta 429s
const all = $input.all();
const total = all.length;
const ok200 = all.filter(i => !i.json.error && i.json.status === 'ok').length;
const dup409 = all.filter(i => i.json.status === 'duplicate_ignored').length;
const rl429 = all.filter(i => i.json.error === 'rate_limit_exceeded').length;
const outros = total - ok200 - dup409 - rl429;

return [{
  json: {
    total,
    ok_200: ok200,
    duplicate_409: dup409,
    rate_limited_429: rl429,
    outros,
    rate_limit_ativado: rl429 >= 5,
    timestamp: new Date().toISOString()
  }
}];
